use std::{env,path::PathBuf};use nomos_engine::Runtime;use signal_nomos::{Request,encode_reply,encode_request};use signal_sema_storage::{ContentHash,FixtureScope,SlotIdentifier};use tokio::{io::{AsyncReadExt,AsyncWriteExt},net::{UnixListener,UnixStream}};
#[tokio::main]async fn main()->Result<(),Box<dyn std::error::Error>>{let mut a=env::args().skip(1);match a.next().as_deref(){Some("daemon")=>{let socket=PathBuf::from(a.next().unwrap_or_else(||"/tmp/new-language-engine/nomos.sock".into()));let sema=PathBuf::from(a.next().unwrap_or_else(||"/tmp/new-language-engine/sema.sock".into()));if let Some(p)=socket.parent(){std::fs::create_dir_all(p)?}let _=std::fs::remove_file(&socket);let l=UnixListener::bind(socket)?;let r=Runtime::new(sema);loop{let(s,_)=l.accept().await?;let r=r.clone();tokio::spawn(async move{let _=serve(s,r).await;});}},Some("transform")=>{let socket=PathBuf::from(a.next().ok_or("socket")?);let hex=a.next().ok_or("schema hash")?;let mut hash=[0;32];for(i,c)in hex.as_bytes().chunks_exact(2).enumerate().take(32){hash[i]=u8::from_str_radix(std::str::from_utf8(c)?,16)?}println!("{:?}",client(&socket,&Request::Transform{scope:FixtureScope(1),schema:ContentHash(hash),output_slot:SlotIdentifier(1)}).await?);Ok(())},_=>Err("usage: nomos-engine daemon [socket] [sema-socket] | transform <socket> <hash>".into())}}
async fn serve(mut s:UnixStream,r:Runtime)->Result<(),Box<dyn std::error::Error>>{let n=s.read_u32_le().await?as usize;let mut b=vec![0;n];s.read_exact(&mut b).await?;let q=rkyv::from_bytes::<Request,rkyv::rancor::Error>(&b)?;let b=encode_reply(&r.request(q).await?).map_err(|e|format!("encode: {e}"))?;s.write_u32_le(b.len()as u32).await?;s.write_all(&b).await?;Ok(())}async fn client(p:&PathBuf,q:&Request)->Result<signal_nomos::Reply,Box<dyn std::error::Error>>{let mut s=UnixStream::connect(p).await?;let b=encode_request(q).map_err(|e|format!("encode: {e}"))?;s.write_u32_le(b.len()as u32).await?;s.write_all(&b).await?;let n=s.read_u32_le().await?as usize;let mut b=vec![0;n];s.read_exact(&mut b).await?;Ok(rkyv::from_bytes::<signal_nomos::Reply,rkyv::rancor::Error>(&b)?)}
